import { workflow, step, branch, http, tpl, gt } from "@blokjs/core";
import validateOrder from "./nodes/validate-order";
import createOrder from "./nodes/create-order";
import httpGet from "@blokjs/api-call";
import respond from "@blokjs/respond";

export default workflow("order-intake", { trigger: http.post("/orders") }, (req) => {
  const validate = step("validate", validateOrder, { body: req.body });

  const stock = step("checkStock", httpGet, {
    url: tpl`https://inv.api/stock/${validate.productId}`,
    method: "GET",
  });

  // stock.inStock is a typed boolean handle. branch reads it as a structural
  // ref — no raw-ctx string, no $ proxy, no footgun. The if-else node still
  // does the work under the hood; the author never sees ctx.
  return branch(stock.inStock, {
    then: () => {
      const order = step("createOrder", createOrder, {
        productId: validate.productId,
        qty: validate.qty,
        stock,
      });
      return step("ok", respond, { status: 201, body: order }, { ephemeral: true });
    },
    else: () =>
      step("no", respond, { status: 409, body: { error: "out of stock" } }, { ephemeral: true }),
  });
});

