// nodes/web/api-call@1.0.0/index.ts
//
// defineNode() — function-first, Zod in / Zod out, pure execute.
// This is the REAL api-call node shipped with Blok.

import { defineNode } from "@blokjs/runner";
import type { JsonLikeObject } from "@blokjs/runner";
import { z } from "zod";
import { runApiCall } from "./util";

export default defineNode({
  name: "api-call",
  description: "Makes HTTP API calls with automatic JSON handling",

  input: z.object({
    url: z.string().url("Must be a valid URL"),
    method: z.string().default("GET"),
    headers: z.record(z.string()).optional().default({}),
    body: z.record(z.unknown()).optional().default({}),
    responseType: z.string().optional().default("json"),
  }),

  output: z.union([
    z.string(),            // text response
    z.record(z.unknown()), // JSON response
  ]),

  async execute(ctx, input) {
    // Fallback to the previous step's data when no body is passed.
    const body =
      Object.keys(input.body).length > 0
        ? (input.body as JsonLikeObject)
        : (ctx.response.data as JsonLikeObject);

    const result = await runApiCall(
      input.url,
      input.method,
      input.headers as JsonLikeObject,
      body,
      input.responseType,
    );

    return result;
  },
});

