// step out (no slot, no handle to read). `as` renames the slot;
// `spread` flattens a multi-output node — so its handle exposes the
// spread keys directly (load.user, load.profile), mirroring how spread
// lands at the top level of state. as/spread stay mutually exclusive,
// enforced at load time exactly as before.
export default workflow("sync-inventory", { trigger: http.post("/sync") }, (req) => {
  // side-effect only: ephemeral -> never written to state, returns no handle
  step("audit", auditLog, { event: "sync.started", at: req.body.ts }, { ephemeral: true });

  // multi-output node: spread flattens result.data -> state.user + state.profile.
  // the handle exposes those same keys: load.user / load.profile.
  const load = step("load", fetchUserAndProfile, {}, { spread: true });

  // rename the persisted slot: stored at state.report; handle still typed.
  const report = step("report", buildReport, {
    user: load.user,
    profile: load.profile,
  });

  // `audit` produced no handle (ephemeral); `report` and the spread
  // keys are read straight off their typed handles.
  return step("respond", respond, {
    body: { report, user: load.user },
  }, { ephemeral: true });
});

