// scans runtimes/go/nodes, copies each into the SDK module under usernodes/,
// and emits cmd/server/register_user_nodes.go:

function generateGoNodeRegistry(nodeNames: string[]): string {
  const importLines = [
    '\tblok "github.com/nickincloud/blok-go"',
    ...nodeNames.map(
      (n, i) => `\tusernode${i} "github.com/nickincloud/blok-go/usernodes/${n}"`,
    ),
  ];
  const callLines = nodeNames.map((_, i) => `\tusernode${i}.Register(registry)`);
  return [
    "// Code generated by blokctl. DO NOT EDIT.",
    "package main",
    "",
    "import (",
    importLines.join("\n"),
    ")",
    "",
    "// AUTO-GENERATED on every dev spawn. A syntax error in any user node",
    "// fails the Go BUILD silently — the supervisor sees a crash, not the CLI.",
    "func registerUserNodes(registry *blok.NodeRegistry) {",
    callLines.join("\n"),
    "}",
  ].join("\n");
}

