// and their schemas — it returns them from the ListNodes RPC (runtime.proto:
// NodeDescriptor { name, input_schema_json, output_schema_json }). We read that
// manifest and generate a typed stub. No per-family special-casing.
//
//   $ blokctl nodes sync
//   ✓ go        4 nodes  -> nodes/*.go.ts
//   ✓ rust      2 nodes  -> nodes/*.rust.ts
//   ✓ java      1 node   -> nodes/*.java.ts
//   ✓ csharp    1 node   -> nodes/*.csharp.ts
//   ✓ php       3 nodes  -> nodes/*.php.ts
//   ✓ ruby      2 nodes  -> nodes/*.ruby.ts
//   ✓ python3   5 nodes  -> nodes/*.python.ts
//
// packages/cli/src/services/nodes-sync.ts (one path for every kind)
import { runtimeRegistry, type NodeDescriptor } from "@blokjs/core";
import { jsonSchemaToTs } from "./schema-codegen";

export async function syncNodes(): Promise<void> {
  for (const kind of runtimeRegistry.kinds()) {                 // go..python3, uniform
    const adapter = runtimeRegistry.adapter(kind);
    const { nodes } = await adapter.listNodes();                // gRPC ListNodes RPC
    for (const node of nodes) {
      await writeStub(kind, node);                              // same for every runtime
    }
  }
}

async function writeStub(kind: string, node: NodeDescriptor): Promise<void> {
  const In = jsonSchemaToTs(node.inputSchemaJson);              // JSON Schema -> TS type
  const Out = jsonSchemaToTs(node.outputSchemaJson);
  const ident = camelCase(node.name);
  const file = `nodes/${node.name}.${stubExt(kind)}.ts`;
  await write(
    file,
    `// GENERATED from ${kind} ListNodes manifest. Do not edit. Run \`blokctl nodes sync\`.\n` +
      `import { runtimeNode } from "@blokjs/core";\n\n` +
      `export const ${ident} = runtimeNode<${In}, ${Out}>(\n` +
      `  ${JSON.stringify(node.name)},\n` +
      `  ${JSON.stringify("runtime." + kind)},\n` +
      `);\n`,
  );
}

